def validate_protocol(states, initial, accepting, transitions, messages):
    trans_map = {}
    for (fr, msg, to) in transitions:
        trans_map[(fr, msg)] = to

    accepting_set = set(accepting)
    current = initial

    for i, msg in enumerate(messages):
        key = (current, msg)
        if key not in trans_map:
            return ("ERROR", i + 1)
        current = trans_map[key]

    if current in accepting_set:
        return ("ACCEPTED", current)
    else:
        return ("REJECTED", len(messages))
